code.C:
#include <stdio.h>
int main() {
    const int T = 1; // single test case as required
    for (int tc = 0; tc < T; ++tc) {
        FILE *fp = fopen("input.txt", "a");
        if (!fp) {
            printf("Could not open file\n");
            return 1;
        }
        fprintf(fp, "5\n10\nabcd\n11\n12.0\n");
        fclose(fp);
        fp = fopen("input.txt", "r");
        if (!fp) {
            printf("Could not open file\n");
            return 1;
        }
        int ch;
        while ((ch = fgetc(fp)) != EOF) {
            putchar(ch);
        }
        fclose(fp);
    }
    return 0;
}

